    85→            ),
    86→            
    87→            className: 'like-button',
    88→            action: (e, journalId, receiverId) => debounceClickLike(e, journalId, receiverId),
    89→            countLike: (count) => <p style={{padding:'0', margin: '0', fontSize: '0.8rem'}}>{formatCounts(count)}</p>
    90→        },
    91→        {
    92→            label: 
