   262→                <motion.div 
   263→                className="newsfeed-header"
   264→                initial={{opacity: 0}}
   265→                animate={{opacity: 1, transition: {type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
   266→                exit={{ opacity: 0, y: -20,
   267→                        transition: { 
   268→                        duration: 0.2,
   269→                        ease: "easeOut"
   270→                        }
   271→                }}
   272→                >
   273→
   274→                    {header_links.map((header_link, index) => (
   275→                        <div key={index} className="header-links">
