   317→                                    </div>
   318→
   319→                                    <div className="name-info-separator">
   320→                                        •
   321→                                    </div>
   322→
   323→                                    <div className="user-info-email-container">
   324→                                        <p className="user-info-email">{journal.users.user_email}</p>
   325→                                    </div>
   326→
   327→                                    <div className="name-info-separator">
   328→                                        •
   329→                                    </div>
   330→
   331→                                    <div className="user-post-date-container">
