   333→                                            {formatPostDate(journal.created_at)}
   334→                                        </p>
   335→                                    </div>
   336→                                </div>
   337→
   338→                                <div className="user-post-settings">
   339→                                    <svg onClick={(e) => handleClickSettings(e, journal.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
   340→                                    {postIdSettings === journal.id && (
   341→                                        <motion.div 
   342→                                        initial={{opacity:0 ,scale:0}}
   343→                                        animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
   344→                                        exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
   345→                                        ref={modalRef} className="setting-modal"
   346→                                        >
   347→                                            <p onClick={() => console.log('clicked')}>{journal.title}</p>
   348→                                        </motion.div>
   349→                                    )}
   350→                                </div>
   351→                                
   352→                            </div>
   353→
   354→                            <div onClick={(e) => viewContent(e, journal.content, parsedContent.wholeText, journal.title, journal.users.id, journal.users.name, journal.users.image_url, journal.created_at, journal.id, journal.has_liked, journal.comment_count?.[0]?.count, journal.has_bookmarked, journal.like_count?.[0].count, journal.bookmark_count?.[0].count, journal.users.badge)} className="content-container">
   355→
   356→                                <div className="feed-text-content-container">
