   402→                                        {icon.countBookmarks && icon.countBookmarks(journal.bookmark_count?.[0].count)}
   403→                                        {icon.iconCount && icon.iconCount(journal?.views)}
   404→                                    </div>  
   405→                                ))
   406→                            )}
   407→
   408→                            <div className="reading-time-container">
   409→                                <p className="reading-time-text">{CalculateText(parsedContent.wholeText)}</p>
   410→                            </div>
   411→                        </div>
   412→                    </div>
   413→                )
   414→            })}
   415→
   416→             <div className="inview" ref={ref}>
   417→                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
   418→            </div>
   419→        </div>
   420→       </AnimatePresence>
   421→        </>
   422→    )
   423→}
